<template><div style="padding:20px"><el-card><template #header><span>邀请好友</span></template><div style="text-align:center;padding:40px"><p>我的邀请码</p><h2>{{ inviteCode }}</h2><el-button type="primary" @click="copyCode">复制邀请码</el-button></div></el-card></div></template>
<script setup>import {ref,onMounted} from "vue";import {ElMessage} from "element-plus";import axios from "axios";const inviteCode=ref("加载中");const copyCode=async()=>{try{await navigator.clipboard.writeText(inviteCode.value);ElMessage.success("已复制")}catch{ElMessage.error("复制失败")}};const loadData=async()=>{try{const res=await axios.get("/api/v1/invitations/my-stats");inviteCode.value=res.data.invite_code||"暂无"}catch(e){inviteCode.value="获取失败"}};onMounted(loadData)</script>
